import React, { createContext, useState, useContext } from 'react';
import en from '../i18/en.json';

const LanguageContext = createContext();

export const LanguageProvider = ({ children }) => {
  const [language, setLanguage] = useState('en');
  const [translations, setTranslations] = useState(en);

  const switchLanguage = (lang) => {
    setLanguage(lang);
    // In a real app, you'd load the json dynamically or from a map
    // For now, we allow switching but might revert to en if others don't exist
    if (lang === 'en') {
      setTranslations(en);
    }
    // Add other languages here if available
  };

  return (
    <LanguageContext.Provider value={{ language, switchLanguage, t: (key) => translations[key] || key }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => useContext(LanguageContext);
